const records = $json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    company_name: r.fields.company_name || '',
    client_slug: r.fields.client_slug || '',
    industry: r.fields.industry || '',
    call_notes: r.fields.call_notes || ''
  }
}));

// Handles webhook, form, and loop input
const body = $json.body || $json;
const formData = $json['Client slug'] !== undefined;
return [{
  json: {
    record_id: body.record_id || '',
    company_name: formData ? $json['Company name'] : (body.company_name || body.client_name || ''),
    client_slug: formData ? $json['Client slug'] : (body.client_slug || ''),
    industry: formData ? ($json['Industry'] || '') : (body.industry || ''),
    call_notes: formData ? $json['Call notes'] : (body.call_notes || '')
  }
}];

const text = $json.choices?.[0]?.message?.content || $json.content?.[0]?.text || $json.output || '{}';
let scope;
try {
  const match = text.match(/\{[\s\S]*\}/);
  scope = match ? JSON.parse(match[0]) : {};
} catch(e) { scope = {}; }

const client = $('Prepare Client Data').item.json;
const prospectTiers = new Set(['starter-build', 'growth-package', 'scale-retainer']);
const tierMap = {
  'starter-package': 'starter-build',
  'growth-build': 'growth-package',
  'growth-package': 'growth-package',
  'scale-build': 'scale-retainer',
  'scale-package': 'scale-retainer',
  'retainer': 'scale-retainer',
  'agency-retainer': 'scale-retainer',
};
const rawTier = String(scope.service_tier || 'starter-build').trim();
const service_tier = prospectTiers.has(rawTier) ? rawTier : (tierMap[rawTier] || 'starter-build');

return [{
  json: {
    record_id: client.record_id,
    client_slug: client.client_slug,
    company_name: client.company_name,
    scope_summary: scope.scope_summary || '',
    service_tier,
    automation_count: scope.automation_count || 1,
    automation_1_name: scope.automation_1_name || '',
    automation_1_description: scope.automation_1_description || '',
    automation_2_name: scope.automation_2_name || '',
    automation_2_description: scope.automation_2_description || '',
    automation_3_name: scope.automation_3_name || '',
    automation_3_description: scope.automation_3_description || '',
    tools_required: Array.isArray(scope.tools_required) ? scope.tools_required.join(', ') : (scope.tools_required || '')
  }
}];
